var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"휴우. 멀리도 왔네.","JPN":"ふう。ずいぶん遠くまで来たね。","ENG":"Phew... This should be far enough.","TWN":"呼，飛很遠了。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"잠깐 쉬자. 이제는 더 못 날겠어.","JPN":"ちょっと休もう。もう飛べない。","ENG":"Let's rest a little here. I don't think I can fly anymore right now.","TWN":"休息一下吧，我飛不動了。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그 냉기 풀풀 날리던 녀석도 여기까지 쫓아오려면 쉽지 않을 거야.","JPN":"あの冷気をがんがん出してたやつも、ここまではそう簡単に追ってこれないはず。","ENG":"Plus, it won't be easy for the icy monster to follow us all the way over to here.","TWN":"那個渾身充滿寒氣的傢伙，想追到這裡應該也沒那麼容易。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"저…… 도와 주셔서 감사합니다. 덕분에 부학회장님이 무사하실 수 있었어요.","JPN":"あの……助けていただいてありがとうございます。おかげさまで副学会長様がご無事でした。","ENG":"Uh... Thank you for helping us. Thanks to you, Vice President is safe.","TWN":"那個……謝謝你幫我們。多虧了你，副學會長才能平安脫險。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신, 루나라고 했죠? 그 괴물에게서 어떻게 살아나온 거예요?","JPN":"あなた、ルナといいましたわね。あの怪物からどうやって生き延びたのですか？","ENG":"You. Your name was Luna, correct? Did you not die to that monster moments before?","TWN":"你，叫露娜對吧？你是怎麼從那個怪物手裡活下來的？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"뭐야, 너 내가 진짜 그냥 평범한 꼬맹인 줄 알았어?","JPN":"なんだよ。あんた、アタシのこと本当にただのガキだと思ってたわけ？","ENG":"Huh? Did you think I was some normie kid?","TWN":"什麼嘛，你以為我真的就是個普通的小鬼嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……그럼 아닌가요?","JPN":"……そうではなかったのですか？","ENG":"...Are you not?","TWN":"……不是嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"당연히 아니지. 난 네가 태어나기 훨씬 전부터 살아 온 그림자거든.","JPN":"当たり前じゃん。アタシはあんたが生まれるずっと前から生きてきたシャドウなんだから。","ENG":"Of course not! I'm a Shadow who's been living way before you were even born.","TWN":"當然不是。我是你還沒出生之前，就活了很久的暗影。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"그림자요?","JPN":"シャドウ？","ENG":"A Shadow?","TWN":"暗影？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그 말은… 당신이 인간 흉내를 내는 침식체라고요?","JPN":"つまり……あなたは人間のふりをした侵食体ということですの？","ENG":"Does that mean... You are a C.O. that mimics humans?","TWN":"你的意思是……你是模仿人類的侵蝕體？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그래. 여기 내 목에 새겨진 문신이 그 증거야.","JPN":"そう。この首に刻まれたタトゥーがその証拠。","ENG":"Yup. And this tattoo on my neck is the proof.","TWN":"是的。我脖子上的紋身就是證據。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"핵만 멀쩡하면 아무리 베이고 박살나도 다시 살아날 수 있지.","JPN":"核さえ無事ならいくら斬られて壊されても再生することができるんだ。","ENG":"I'll be able to resurrect if my core remains intact, no matter how brutally I was crushed.","TWN":"只要核心沒事，就算再怎麼被砍斷、砸碎，我也能復活。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"와, 와, 와아…… 그림자는 처음 봤어요. 정말 사람이랑 똑같네요.","JPN":"わ、わ、わあ……シャドウなんて初めてです。本当に人間そっくりですね。","ENG":"W-wow... I've never met a Shadow before... You really do look exactly like us.","TWN":"哇，哇，哇啊……我還是第一次看到暗影。真的跟人一模一樣。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"크크큭, 이것도 다 오래 살아남은 덕분 아니겠어?","JPN":"くくく、それもこれも長く生きてきたおかげってやつ？","ENG":"Kekeke... It's all thanks to being alive all this time, no?","TWN":"呵呵呵，這也都是因為活了更久的緣故吧？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"좋은 정보 감사합니다. 어서 관리국에 신고해야겠네요.","JPN":"有益な情報をありがとうございます。早く管理局に通報しなければ。","ENG":"Thank you for that information. I should now report you to the Administration.","TWN":"謝謝你的情報。我要馬上向管理局報告。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그림자 정도의 침식체라면 가만히 있어도 침식파를 퍼뜨리니까요. 늦기 전에 대처해야죠.","JPN":"シャドウほどの侵食体ならば、そこに居るだけでも侵食波をまき散らします。手遅れになる前に対処しなければいけませんからね。","ENG":"A Shadow emits Corruption ray even if it stays idle. We must deal with you before it is too late.","TWN":"因為暗影這類的侵蝕體，哪怕什麼都不做也會釋放侵蝕波。必須趁早處理掉。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"그렇구나…. 역시 박식하세요, 부학회장님.","JPN":"そうなんですね……さすがによくご存じです、副学会長様。","ENG":"I see... You're very knowledgeable, ma'am?","TWN":"這樣啊……你果然很博學，副學會長。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};